const canvas = document.querySelector("#game");
const ctx = canvas.getContext("2d");

const scoreEl = document.querySelector("#score");
const bestEl = document.querySelector("#best");
const stateText = document.querySelector("#stateText");
const overlay = document.querySelector("#overlay");
const overlayTitle = document.querySelector("#overlayTitle");
const overlayText = document.querySelector("#overlayText");
const primaryAction = document.querySelector("#primaryAction");
const leftButton = document.querySelector("#leftButton");
const rightButton = document.querySelector("#rightButton");
const pauseButton = document.querySelector("#pauseButton");

const storageKey = "little-stairs-best";
const keys = new Set();
const pointerInput = { left: false, right: false };
const sprites = {
  idle: loadSprite("data:image/png;base64,"),
  move: loadSprite("data:image/gif;base64,"),
};

let bestScore = Number(localStorage.getItem(storageKey) || 0);
let width = 420;
let height = 680;
let lastTime = 0;
let gameState = "menu";
let scrollSpeed = 86;
let score = 0;
let distance = 0;
let combo = 0;
let platformId = 0;
let platforms = [];
let particles = [];

const player = {
  x: 0,
  y: 0,
  w: 42,
  h: 48,
  vx: 0,
  vy: 0,
  facing: 1,
  moving: false,
  grounded: false,
  color: "#ffd166",
};

const config = {
  gravity: 1480,
  moveSpeed: 310,
  airControl: 0.88,
  jumpNudge: -90,
  platformGapMin: 64,
  platformGapMax: 92,
  minPlatformWidth: 68,
  maxPlatformWidth: 128,
};

function resizeCanvas() {
  const rect = canvas.getBoundingClientRect();
  const dpr = Math.max(1, Math.min(window.devicePixelRatio || 1, 2));
  width = rect.width;
  height = rect.height;
  canvas.width = Math.floor(width * dpr);
  canvas.height = Math.floor(height * dpr);
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
}

function randomBetween(min, max) {
  return min + Math.random() * (max - min);
}

function clamp(value, min, max) {
  return Math.max(min, Math.min(max, value));
}

function loadSprite(src) {
  const image = new Image();
  image.src = src;
  return image;
}

function isSpriteReady(image) {
  return image.complete && image.naturalWidth > 0;
}

function platformTypeFor(scoreValue) {
  const roll = Math.random();
  if (scoreValue > 520 && roll < 0.12) return "spike";
  if (scoreValue > 260 && roll < 0.27) return "crumble";
  if (scoreValue > 150 && roll < 0.38) return "moving";
  if (scoreValue > 80 && roll < 0.18) return "spring";
  return "normal";
}

function addPlatform(y, options = {}) {
  const type = options.type || platformTypeFor(score);
  const baseWidth =
    type === "spike"
      ? randomBetween(74, 112)
      : randomBetween(config.minPlatformWidth, config.maxPlatformWidth);
  const platform = {
    id: platformId++,
    x: options.x ?? randomBetween(16, Math.max(17, width - baseWidth - 16)),
    y,
    w: options.w ?? baseWidth,
    h: type === "spike" ? 18 : 16,
    type,
    vx: type === "moving" ? (Math.random() < 0.5 ? -54 : 54) : 0,
    broken: false,
    touched: false,
  };
  platforms.push(platform);
  return platform;
}

function seedPlatforms() {
  platforms = [];
  platformId = 0;
  const startY = height - 82;
  addPlatform(startY, {
    x: width / 2 - 72,
    w: 144,
    type: "normal",
  });
  for (let y = startY - 78; y > -60; y -= randomBetween(68, 88)) {
    addPlatform(y, { type: "normal" });
  }
  let bottomY = startY + 78;
  while (bottomY < height + 160) {
    addPlatform(bottomY, { type: "normal" });
    bottomY += randomBetween(70, 92);
  }
}

function resetGame() {
  resizeCanvas();
  score = 0;
  distance = 0;
  combo = 0;
  scrollSpeed = 86;
  particles = [];
  seedPlatforms();
  const start = platforms[0];
  player.x = start.x + start.w / 2 - player.w / 2;
  player.y = start.y - player.h;
  player.vx = 0;
  player.vy = 0;
  player.facing = 1;
  player.moving = false;
  player.grounded = true;
  setState("playing");
}

function setState(next) {
  gameState = next;
  overlay.classList.toggle("is-hidden", next === "playing");
  pauseButton.textContent = next === "paused" ? "▶" : "Ⅱ";

  if (next === "menu") {
    stateText.textContent = "準備出發";
    overlayTitle.textContent = "準備好了嗎？";
    overlayText.textContent = "找準樓梯，越往下越厲害。";
    primaryAction.textContent = "開始";
  }

  if (next === "playing") {
    stateText.textContent = combo > 2 ? `連續踏穩 ${combo}` : "往下走";
  }

  if (next === "paused") {
    stateText.textContent = "暫停中";
    overlayTitle.textContent = "先喘一下";
    overlayText.textContent = "回到節奏後再繼續。";
    primaryAction.textContent = "繼續";
  }

  if (next === "gameover") {
    stateText.textContent = "遊戲結束";
    overlayTitle.textContent = "再來一次";
    overlayText.textContent = `這次走了 ${score} 階。`;
    primaryAction.textContent = "重新開始";
  }
}

function finishGame() {
  if (gameState !== "playing") return;
  bestScore = Math.max(bestScore, score);
  localStorage.setItem(storageKey, String(bestScore));
  bestEl.textContent = bestScore;
  burst(player.x + player.w / 2, player.y + player.h / 2, "#ef476f", 18);
  setState("gameover");
}

function burst(x, y, color, amount) {
  for (let i = 0; i < amount; i += 1) {
    particles.push({
      x,
      y,
      vx: randomBetween(-150, 150),
      vy: randomBetween(-210, 60),
      life: randomBetween(0.35, 0.75),
      age: 0,
      color,
      size: randomBetween(2, 5),
    });
  }
}

function updatePlatforms(dt) {
  const gapBoost = clamp(score / 1500, 0, 1);
  for (const platform of platforms) {
    platform.y -= scrollSpeed * dt;
    if (platform.type === "moving") {
      platform.x += platform.vx * dt;
      if (platform.x < 12 || platform.x + platform.w > width - 12) {
        platform.x = clamp(platform.x, 12, width - platform.w - 12);
        platform.vx *= -1;
      }
    }
    if (platform.broken) {
      platform.y += 185 * dt;
      platform.h = Math.max(0, platform.h - 22 * dt);
    }
  }

  platforms = platforms.filter((platform) => platform.y > -50 && platform.h > 2);

  const lowestY = platforms.reduce((max, platform) => Math.max(max, platform.y), -100);
  let y = lowestY;
  while (y < height + 140) {
    y += randomBetween(
      config.platformGapMin + gapBoost * 12,
      config.platformGapMax + gapBoost * 24,
    );
    addPlatform(y);
  }
}

function updatePlayer(dt) {
  const input =
    (keys.has("ArrowRight") || keys.has("KeyD") || pointerInput.right ? 1 : 0) -
    (keys.has("ArrowLeft") || keys.has("KeyA") || pointerInput.left ? 1 : 0);
  const control = player.grounded ? 1 : config.airControl;
  const targetVx = input * config.moveSpeed;
  player.vx += (targetVx - player.vx) * clamp(14 * dt * control, 0, 1);

  if (input !== 0) {
    player.facing = input;
  }
  player.moving = input !== 0;

  const previousBottom = player.y + player.h;
  player.vy += config.gravity * dt;
  player.x += player.vx * dt;
  player.y += player.vy * dt;
  player.y -= scrollSpeed * dt;
  player.grounded = false;

  if (player.x < -player.w) player.x = width;
  if (player.x > width) player.x = -player.w;

  for (const platform of platforms) {
    if (platform.broken || platform.type === "spike") continue;
    const bottom = player.y + player.h;
    const overlapsX = player.x + player.w > platform.x + 4 && player.x < platform.x + platform.w - 4;
    const crossingTop = previousBottom <= platform.y + 6 && bottom >= platform.y;
    if (player.vy >= 0 && overlapsX && crossingTop) {
      player.y = platform.y - player.h;
      player.vy = platform.type === "spring" ? -520 : config.jumpNudge;
      player.grounded = platform.type !== "spring";

      if (!platform.touched) {
        platform.touched = true;
        combo += 1;
        score += platform.type === "spring" ? 8 : 4;
        if (combo > 2) score += Math.min(6, combo);
        burst(player.x + player.w / 2, platform.y, platform.type === "spring" ? "#4cc9f0" : "#54d688", 7);
      }

      if (platform.type === "crumble") {
        platform.broken = true;
        burst(platform.x + platform.w / 2, platform.y, "#ffd166", 12);
      }
      break;
    }
  }

  for (const platform of platforms) {
    if (platform.type !== "spike") continue;
    const hit =
      player.x < platform.x + platform.w &&
      player.x + player.w > platform.x &&
      player.y < platform.y + platform.h &&
      player.y + player.h > platform.y;
    if (hit) finishGame();
  }

  if (player.y < 16 || player.y > height + 56) {
    finishGame();
  }

  if (!player.grounded && player.vy > 280) {
    combo = 0;
  }
}

function updateParticles(dt) {
  for (const particle of particles) {
    particle.age += dt;
    particle.vy += 520 * dt;
    particle.x += particle.vx * dt;
    particle.y += particle.vy * dt;
  }
  particles = particles.filter((particle) => particle.age < particle.life);
}

function update(dt) {
  scrollSpeed = 86 + Math.min(106, score * 0.11);
  distance += scrollSpeed * dt;
  score = Math.max(score, Math.floor(distance / 18));
  updatePlatforms(dt);
  updatePlayer(dt);
  updateParticles(dt);
  scoreEl.textContent = score;
  bestEl.textContent = Math.max(bestScore, score);
  if (gameState === "playing") {
    stateText.textContent = combo > 2 ? `連續踏穩 ${combo}` : "往下走";
  }
}

function drawBackground() {
  const sky = ctx.createLinearGradient(0, 0, 0, height);
  sky.addColorStop(0, "#26364a");
  sky.addColorStop(0.52, "#172433");
  sky.addColorStop(1, "#101820");
  ctx.fillStyle = sky;
  ctx.fillRect(0, 0, width, height);

  ctx.strokeStyle = "rgba(255,255,255,0.06)";
  ctx.lineWidth = 1;
  const offset = (distance * 0.28) % 42;
  for (let y = -42; y < height + 42; y += 42) {
    ctx.beginPath();
    ctx.moveTo(0, y - offset);
    ctx.lineTo(width, y - offset + 18);
    ctx.stroke();
  }

  ctx.fillStyle = "rgba(239,71,111,0.9)";
  for (let x = 0; x < width + 28; x += 28) {
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x + 14, 22);
    ctx.lineTo(x + 28, 0);
    ctx.closePath();
    ctx.fill();
  }
}

function drawPlatform(platform) {
  ctx.save();
  ctx.translate(platform.x, platform.y);

  if (platform.type === "spike") {
    ctx.fillStyle = "#ef476f";
    for (let x = 0; x < platform.w; x += 18) {
      ctx.beginPath();
      ctx.moveTo(x, platform.h);
      ctx.lineTo(x + 9, 0);
      ctx.lineTo(x + 18, platform.h);
      ctx.closePath();
      ctx.fill();
    }
    ctx.restore();
    return;
  }

  const colors = {
    normal: ["#54d688", "#2f9d66"],
    moving: ["#4cc9f0", "#207fa3"],
    crumble: ["#ffd166", "#b98723"],
    spring: ["#b388ff", "#7651c9"],
  };
  const [top, bottom] = colors[platform.type] || colors.normal;
  const platformGradient = ctx.createLinearGradient(0, 0, 0, platform.h);
  platformGradient.addColorStop(0, top);
  platformGradient.addColorStop(1, bottom);
  ctx.fillStyle = platformGradient;
  roundRect(ctx, 0, 0, platform.w, platform.h, 7);
  ctx.fill();

  ctx.fillStyle = "rgba(255,255,255,0.18)";
  roundRect(ctx, 8, 3, platform.w - 16, 3, 2);
  ctx.fill();

  if (platform.type === "moving") {
    ctx.fillStyle = "rgba(16,24,32,0.62)";
    ctx.fillRect(platform.w / 2 - 12, 5, 24, 4);
  }

  if (platform.type === "crumble") {
    ctx.strokeStyle = "rgba(50,35,15,0.34)";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(platform.w * 0.32, 2);
    ctx.lineTo(platform.w * 0.42, platform.h - 2);
    ctx.moveTo(platform.w * 0.62, 3);
    ctx.lineTo(platform.w * 0.54, platform.h - 1);
    ctx.stroke();
  }

  if (platform.type === "spring") {
    ctx.strokeStyle = "#f7f4e8";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(platform.w / 2 - 16, -5);
    ctx.lineTo(platform.w / 2 + 16, -5);
    ctx.stroke();
  }

  ctx.restore();
}

function drawPlayer() {
  const centerX = player.x + player.w / 2;
  const sprite = player.moving ? sprites.move : sprites.idle;
  const spriteSize = clamp(width * 0.22, 86, 100);
  const spriteY = player.y + player.h - spriteSize + 8;

  ctx.save();

  ctx.fillStyle = "rgba(0,0,0,0.2)";
  ctx.beginPath();
  ctx.ellipse(centerX, player.y + player.h + 3, 22, 6, 0, 0, Math.PI * 2);
  ctx.fill();

  if (isSpriteReady(sprite)) {
    ctx.translate(centerX, spriteY + spriteSize / 2);
    ctx.scale(player.facing, 1);
    ctx.drawImage(sprite, -spriteSize / 2, -spriteSize / 2, spriteSize, spriteSize);
    ctx.restore();
    return;
  }

  ctx.translate(centerX, player.y);
  ctx.fillStyle = "#42d392";
  roundRect(ctx, -13, 22, 26, 22, 7);
  ctx.fill();

  ctx.strokeStyle = "#f7f4e8";
  ctx.lineWidth = 4;
  ctx.lineCap = "round";
  ctx.beginPath();
  ctx.moveTo(-9, 42);
  ctx.lineTo(-14, 49);
  ctx.moveTo(9, 42);
  ctx.lineTo(14, 49);
  ctx.stroke();

  ctx.strokeStyle = "#ffd7a3";
  ctx.beginPath();
  ctx.moveTo(-11, 28);
  ctx.lineTo(-19, 34);
  ctx.moveTo(11, 28);
  ctx.lineTo(19, 34);
  ctx.stroke();

  ctx.fillStyle = "#ffd7a3";
  ctx.beginPath();
  ctx.arc(0, 14, 13, 0, Math.PI * 2);
  ctx.fill();

  ctx.fillStyle = "#27313b";
  ctx.beginPath();
  ctx.arc(-5, 12, 2, 0, Math.PI * 2);
  ctx.arc(5, 12, 2, 0, Math.PI * 2);
  ctx.fill();

  ctx.strokeStyle = "#27313b";
  ctx.lineWidth = 1.8;
  ctx.beginPath();
  ctx.arc(0, 15, 5, 0.15 * Math.PI, 0.85 * Math.PI);
  ctx.stroke();

  ctx.fillStyle = "#27313b";
  ctx.beginPath();
  ctx.arc(-2, 2, 12, Math.PI, 2 * Math.PI);
  ctx.fill();

  ctx.restore();
}

function drawParticles() {
  for (const particle of particles) {
    const alpha = 1 - particle.age / particle.life;
    ctx.globalAlpha = alpha;
    ctx.fillStyle = particle.color;
    ctx.beginPath();
    ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.globalAlpha = 1;
}

function drawWarning() {
  const danger = clamp((42 - player.y) / 42, 0, 1);
  if (danger <= 0) return;
  ctx.fillStyle = `rgba(239, 71, 111, ${danger * 0.22})`;
  ctx.fillRect(0, 0, width, height);
}

function draw() {
  ctx.clearRect(0, 0, width, height);
  drawBackground();
  for (const platform of platforms) {
    drawPlatform(platform);
  }
  drawParticles();
  drawPlayer();
  drawWarning();
}

function roundRect(context, x, y, w, h, radius) {
  const r = Math.min(radius, w / 2, h / 2);
  context.beginPath();
  context.moveTo(x + r, y);
  context.lineTo(x + w - r, y);
  context.quadraticCurveTo(x + w, y, x + w, y + r);
  context.lineTo(x + w, y + h - r);
  context.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
  context.lineTo(x + r, y + h);
  context.quadraticCurveTo(x, y + h, x, y + h - r);
  context.lineTo(x, y + r);
  context.quadraticCurveTo(x, y, x + r, y);
  context.closePath();
}

function frame(time) {
  const dt = Math.min((time - lastTime) / 1000 || 0, 0.033);
  lastTime = time;
  if (gameState === "playing") {
    update(dt);
  } else {
    updateParticles(dt);
  }
  draw();
  requestAnimationFrame(frame);
}

function togglePause() {
  if (gameState === "playing") {
    setState("paused");
    return;
  }
  if (gameState === "paused") {
    setState("playing");
  }
}

function setPointer(direction, active) {
  pointerInput[direction] = active;
}

function bindHold(button, direction) {
  button.addEventListener("pointerdown", (event) => {
    event.preventDefault();
    button.setPointerCapture(event.pointerId);
    setPointer(direction, true);
    if (gameState === "menu" || gameState === "gameover") resetGame();
  });

  button.addEventListener("pointerup", () => setPointer(direction, false));
  button.addEventListener("pointercancel", () => setPointer(direction, false));
  button.addEventListener("pointerleave", () => setPointer(direction, false));
}

primaryAction.addEventListener("click", () => {
  if (gameState === "paused") {
    setState("playing");
    return;
  }
  resetGame();
});

pauseButton.addEventListener("click", () => {
  if (gameState === "menu" || gameState === "gameover") {
    resetGame();
    return;
  }
  togglePause();
});

bindHold(leftButton, "left");
bindHold(rightButton, "right");

window.addEventListener("keydown", (event) => {
  if (["ArrowLeft", "ArrowRight", "KeyA", "KeyD", "Space", "Enter", "KeyP"].includes(event.code)) {
    event.preventDefault();
  }
  if (event.code === "Enter" && (gameState === "menu" || gameState === "gameover")) {
    resetGame();
    return;
  }
  if (event.code === "Space" || event.code === "KeyP") {
    togglePause();
    return;
  }
  keys.add(event.code);
});

window.addEventListener("keyup", (event) => {
  keys.delete(event.code);
});

window.addEventListener("resize", () => {
  resizeCanvas();
  if (gameState === "menu") {
    seedPlatforms();
    player.x = width / 2 - player.w / 2;
    player.y = height - 140;
  }
});

bestEl.textContent = bestScore;
resizeCanvas();
seedPlatforms();
player.x = width / 2 - player.w / 2;
player.y = height - 140;
draw();
requestAnimationFrame(frame);

